43	// TestBeadReviewCollapseGolden is the byte-equivalence gate for FEAT-022 §4
44	// stage B: agent.BuildReviewPrompt — which the post-collapse CLI handler
45	// invokes directly — must produce bytes identical to the committed golden
46	// when run against the fixture inputs. The fixture deliberately includes <,
47	// >, &, ", and ' so any divergence in the XML-escape semantics surfaces
48	// here rather than as silent prompt drift.
49	//
50	// Regenerate the golden with: UPDATE_GOLDEN=1 go test -run TestBeadReviewCollapseGolden ./cmd/...
51	func TestBeadReviewCollapseGolden(t *testing.T) {
52		b, refs, rev, diff, root := beadReviewFixture(t)
53		got := agent.BuildReviewPrompt(b, 1, rev, diff, root, refs)
54	
55		goldenPath := filepath.Join("testdata", "bead_review", "collapse_golden.txt")
56		if os.Getenv("UPDATE_GOLDEN") != "" {
57			if err := os.WriteFile(goldenPath, []byte(got), 0o644); err != nil {
58				t.Fatalf("write golden: %v", err)
59			}
60		}
61	
62		want, err := os.ReadFile(goldenPath)
63		if err != nil {
64			t.Fatalf("read golden: %v", err)
65		}
66		if got != string(want) {
67			t.Fatalf("review prompt diverged from golden:\n--- got ---\n%s\n--- want ---\n%s", got, string(want))
68		}
69	
70		for _, ch := range []string{"<", ">", "&", "\"", "'"} {
71			if !strings.Contains(string(want), ch) && !strings.Contains(string(want), xmlEscapeChar(ch)) {
72				t.Errorf("golden must contain XML-escape-sensitive char %q (raw or escaped)", ch)
73			}
74		}
75	}
