77	func xmlEscapeChar(ch string) string {
78		switch ch {
79		case "<":
80			return "&lt;"
81		case ">":
82			return "&gt;"
83		case "&":
84			return "&amp;"
85		case "\"":
86			return "&#34;"
87		case "'":
88			return "&#39;"
89		}
90		return ch
91	}
